import React, { useEffect, useState } from "react";
import "./PersonalAIMentor.css";

const firstMessages = {
  INTP: "გამარჯობა 😊 მოდი ერთად გავაანალიზოთ შენი ძლიერი მხარეები.",
  ENFP: "გამარჯობა 🌟 როგორ შემიძლია დაგეხმარო უკეთ გაიცნო შენი შესაძლებლობები?",
  ESFJ: "გამარჯობა 💛 გინდა ვისაუბროთ შენს ურთიერთობებსა და მიზნებზე?",
  DEFAULT: "გამარჯობა 😊 როგორ შემიძლია დაგეხმარო, რომ უკეთ გაიცნო შენი ფსიქოტიპი?"
};

export default function PersonalAIMentor() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [mbti, setMbti] = useState("");

  useEffect(() => {
    const results = JSON.parse(localStorage.getItem("savedResults")) || [];
    const lastType = results[results.length - 1];
    setMbti(lastType);

    const first =
      firstMessages[lastType] || firstMessages.DEFAULT;

    setMessages([{ role: "ai", text: first }]);
  }, []);

  const sendMessage = () => {
    if (!input.trim()) return;

    setMessages(prev => [...prev, { role: "user", text: input }]);

    //  დროებითი პასუხი სანამ backend ჩავრთავთ
    setTimeout(() => {
      setMessages(prev => [
        ...prev,
        {
          role: "ai",
          text: `შენი ტიპია ${mbti}. მალე უფრო ჭკვიან პასუხებს მოგცემ 😊`
        }
      ]);
    }, 600);

    setInput("");
  };

  return (
    <div className="ai-mentor">
      <div className="ai-header">Personal AI Mentor</div>

      <div className="ai-messages">
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>
            {m.text}
          </div>
        ))}
      </div>

      <div className="ai-input">
        <textarea
        value={input}
        onChange={(e) => setInput(e.target.value)}
        placeholder="მომწერე..."
        rows="1"
        className="ai-textarea"
/>
        <button onClick={sendMessage}>გაგზავნა</button>
      </div>
    </div>
  );
}
